import { readFile, writeFile } from 'node:fs/promises';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';

const root = dirname(dirname(fileURLToPath(import.meta.url)));

const appFragments = [
  'frontend/js/app/00-state.js',
  'frontend/js/app/10-ui-core.js',
  'frontend/js/app/20-routes.js',
  'frontend/js/app/30-settings-import.js',
  'frontend/js/app/40-actions.js',
  'frontend/js/app/50-feedback-bootstrap.js',
];

const banner = '// Generated by scripts/build-app-bundle.mjs. Edit frontend/js/app/*.js instead.\n';

async function readFragment(path) {
  return readFile(join(root, path), 'utf8');
}

export async function buildAppBundle({ check = false } = {}) {
  const body = (await Promise.all(appFragments.map(readFragment)))
    .map((source) => source.trimEnd())
    .join('\n\n');
  const generated = `${banner}(function () {\n${body}\n})();\n`;
  const targetPath = join(root, 'frontend/js/app.js');

  if (check) {
    const current = await readFile(targetPath, 'utf8');
    if (current !== generated) {
      throw new Error('frontend/js/app.js is out of date. Run pnpm build to regenerate it from frontend/js/app/*.js.');
    }
    return generated;
  }

  await writeFile(targetPath, generated);
  return generated;
}

if (import.meta.url === `file://${process.argv[1]}`) {
  await buildAppBundle({ check: process.argv.includes('--check') });
}
